import React from 'react'

const SearchItem = ({search}) => {
  return (
    <form className="searchForm" onSubmit='handleSearchBar'>
    <label htmlFor="search">Search</label>
    <input type="text" placeholder="Search-Items..."  />
    </form>
  )
}

export default SearchItem
